// Parse expense text and extract amount and description
const text = $input.first().json.message.text;
const userId = $input.first().json.message.from.id;
const userName = $input.first().json.message.from.first_name || 'Unknown';
const chatId = $input.first().json.message.chat.id;

// Extract amount and description using regex
const match = text.match(/^(\d+(?:\.\d{2})?)\s+(.+)$/);

if (match) {
  const amount = parseFloat(match[1]);
  const description = match[2].trim();
  const currentDate = new Date();
  const dateStr = currentDate.toLocaleDateString('vi-VN');
  const timeStr = currentDate.toLocaleTimeString('vi-VN');

  // Auto-categorize based on keywords
  let category = 'Khác';
  const desc = description.toLowerCase();

  if (desc.includes('ăn') || desc.includes('cafe') || desc.includes('uống') || desc.includes('trưa') || desc.includes('sáng') || desc.includes('tối')) {
    category = 'Ăn uống';
  } else if (desc.includes('xăng') || desc.includes('xe') || desc.includes('grab') || desc.includes('taxi')) {
    category = 'Di chuyển';
  } else if (desc.includes('mua') || desc.includes('shopping') || desc.includes('quần áo') || desc.includes('giày')) {
    category = 'Mua sắm';
  } else if (desc.includes('điện') || desc.includes('nước') || desc.includes('nhà') || desc.includes('tiền nhà')) {
    category = 'Sinh hoạt';
  } else if (desc.includes('game') || desc.includes('phim') || desc.includes('giải trí')) {
    category = 'Giải trí';
  }

  return [{
    json: {
      userId: userId,
      userName: userName,
      chatId: chatId,
      amount: amount,
      description: description,
      category: category,
      date: dateStr,
      time: timeStr,
      timestamp: currentDate.toISOString()
    }
  }];
} else {
  return [{
    json: {
      error: 'Invalid format',
      chatId: chatId,
      originalText: text
    }
  }];
}

