// Filter today's expenses and calculate totals
const input = $input.all();
const chatId = $('Telegram Webhook').first().json.message.chat.id;
const today = new Date().toLocaleDateString('vi-VN');

if (input.length === 0 || !input[0].json) {
  return [{
    json: {
      chatId: chatId,
      message: '📊 Chưa có chi tiêu nào hôm nay!\n\n💡 Hãy thêm chi tiêu đầu tiên bằng cách gửi:\n[số tiền] [mô tả]\n\nVí dụ: 50000 ăn trưa'
    }
  }];
}

const expenses = input.filter(item => {
  const itemDate = item.json[0]; // Date is in column A
  return itemDate === today;
});

if (expenses.length === 0) {
  return [{
    json: {
      chatId: chatId,
      message: '📊 Chưa có chi tiêu nào hôm nay!\n\n💡 Hãy thêm chi tiêu đầu tiên bằng cách gửi:\n[số tiền] [mô tả]\n\nVí dụ: 50000 ăn trưa'
    }
  }];
}

let total = 0;
let expenseList = '📊 Chi tiêu hôm nay (' + today + '):\n\n';
const categories = {};

expenses.forEach((expense, index) => {
  const amount = parseFloat(expense.json[2]); // Amount is in column C
  const description = expense.json[3]; // Description is in column D
  const category = expense.json[4]; // Category is in column E
  const time = expense.json[1]; // Time is in column B

  total += amount;
  expenseList += `${index + 1}. 💰 ${amount.toLocaleString('vi-VN')} VND\n   📝 ${description}\n   📂 ${category} • 🕒 ${time}\n\n`;

  if (categories[category]) {
    categories[category] += amount;
  } else {
    categories[category] = amount;
  }
});

expenseList += `💯 Tổng cộng: ${total.toLocaleString('vi-VN')} VND\n\n`;
expenseList += '📈 Theo danh mục:\n';

for (const [category, amount] of Object.entries(categories)) {
  expenseList += `• ${category}: ${amount.toLocaleString('vi-VN')} VND\n`;
}

return [{
  json: {
    chatId: chatId,
    message: expenseList
  }
}];
